package dev.harrison.rendacomcarro.attachment;import dev.harrison.rendacomcarro.attachment.application.*;import dev.harrison.rendacomcarro.attachment.domain.OwnerType;import org.junit.jupiter.api.Test;import org.springframework.mock.web.MockMultipartFile;import java.util.UUID;import static org.assertj.core.api.Assertions.assertThatThrownBy;class AttachmentServiceTest {@Test void rejectsExecutableAttachment(){var file=new MockMultipartFile("file","malware.exe","application/octet-stream",new byte[]{1,2,3});var service=new AttachmentService(null,null);assertThatThrownBy(()->service.store(OwnerType.EXPENSE,UUID.randomUUID(),file)).isInstanceOf(InvalidAttachmentException.class);}}
